import { NextRequest, NextResponse } from "next/server";
import { createServerClient } from "@supabase/ssr";

export async function middleware(req: NextRequest) {
  const res = NextResponse.next();
  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        get(name) {
          return req.cookies.get(name)?.value;
        },
        set(name, value, options) {
          res.cookies.set({ name, value, ...options });
        },
        remove(name, options) {
          res.cookies.set({ name, value: "", expires: new Date(0), ...options });
        },
      },
    }
  );

  const { data: userData } = await supabase.auth.getUser();
  const user = userData.user;

  const { data: profile } = await supabase
    .from("profile")
    .select("admin_user_id")
    .limit(1)
    .maybeSingle();

  const path = req.nextUrl.pathname;
  const isInit = path.startsWith("/admin/init");

  if (!user) {
    const url = req.nextUrl.clone();
    url.pathname = "/";
    url.searchParams.set("auth", "required");
    url.searchParams.set("next", req.nextUrl.pathname);
    return NextResponse.redirect(url);
  }

  // If no profile exists yet, only allow /admin/init
  if (!profile) {
    if (isInit) return res;
    const url = req.nextUrl.clone();
    url.pathname = "/admin/init";
    return NextResponse.redirect(url);
  }

  const isAdmin = !!profile.admin_user_id && profile.admin_user_id === user.id;
  if (!isAdmin) {
    const url = req.nextUrl.clone();
    url.pathname = "/";
    url.searchParams.set("auth", "forbidden");
    return NextResponse.redirect(url);
  }

  return res;
}

export const config = {
  matcher: ["/admin/:path*"],
};
